```javascript
/**
 * 创建一个 debounce（防抖）函数
 * @param {Function} fn      要防抖的函数
 * @param {number}   delay   延迟时间（毫秒）
 * @param {boolean}  leading 是否在延迟开始前立即执行一次（可选，默认 false）
 * @returns {Function} 防抖后的函数
 */
function debounce(fn, delay, leading = false) {
  let timer = null

  const debounced = function (...args) {
    const context = this

    // 如果已有定时器，清除它——"重置等待"
    if (timer) clearTimeout(timer)

    if (leading && !timer) {
      // leading 模式：首次调用立即执行，之后在延迟期间内不再触发
      fn.apply(context, args)
    }

    timer = setTimeout(() => {
      if (leading) {
        // leading 模式下，定时器到点只重置标记，不重复执行
        timer = null
      } else {
        // trailing 模式（默认）：定时器到点才执行
        fn.apply(context, args)
        timer = null
      }
    }, delay)
  }

  // 提供一个取消方法，方便外部手动终止
  debounced.cancel = function () {
    if (timer) {
      clearTimeout(timer)
      timer = null
    }
  }

  return debounced
}
```

**核心思路**：debounce 的本质是"把 N 次密集调用合并成一次"。每次调用都重置计时器，只有当连续调用停止超过 `delay` 毫秒后，函数才会真正执行。

**三个要点**：

1. **`this` 绑定** — 用 `fn.apply(context, args)` 而不是直接 `fn(args)`，确保调用时的上下文（比如 DOM 事件里的 `this`）不会丢失
2. **leading / trailing 模式** — trailing（默认）：等安静下来才执行，适合搜索输入框。leading：第一次立即执行，适合按钮防重复提交
3. **`cancel()`** — 竞态场景（比如组件卸载时）需要能手动清掉待执行的定时器，避免回调在错误的上下文中触发

用个例子验证一下：

```javascript
const log = debounce((msg) => console.log(msg, Date.now()), 300)

log('a')  // 重置计时器
log('b')  // 重置计时器
log('c')  // 重置计时器
// 300ms 后只输出一次 "c"

log.cancel() // 直接取消，什么都不会输出
```

